import numpy as np

def predict(frame, action):
    out = frame.copy()
    # actions 6, 7 (and others) are no-ops in the observed data
    if action == 5:
        # action 5 paints color 3 into row 53, advancing one column to the left.
        row = 53
        cols = np.where(out[row] == 3)[0]
        if cols.size == 0:
            c = 63               # start at the right edge
        else:
            c = int(cols.min()) - 1   # one cell left of the current leftmost 3
        if 0 <= c < out.shape[1]:
            out[row, c] = 3
    return out
